                  <div className="py-20 flex flex-col items-center justify-center text-slate-400 space-y-4">
                    <div className="p-8 bg-slate-50 rounded-full border border-slate-100"><BoxIcon className="w-12 h-12"/></div>
                    <p className="text-lg font-medium">Aucun {currentTab === 'inventory' ? 'produit' : 'pack'} trouvé.</p>
                    <button onClick={currentTab === 'inventory' ? openAddModal : openPackModal} className="text-indigo-600 font-bold hover:underline">Créer le premier maintenant</button>
