      )}

      {/* Add / Edit Product Modal */}
      {(isAddProductOpen || isEditOpen) && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl p-10 max-h-[90vh] overflow-y-auto animate-fade-in-scale scrollbar-hide">
             <div className="flex justify-between items-center mb-8">
                <h2 className="text-2xl font-black tracking-tight">{isEditOpen ? 'Mise à jour' : 'Nouveau Produit'}</h2>
                <button onClick={() => { setIsAddProductOpen(false); setIsEditOpen(false); }} className="p-3 hover:bg-slate-100 rounded-full transition-colors"><XIcon className="w-6 h-6"/></button>
             </div>
             <form onSubmit={isEditOpen ? (e) => { e.preventDefault(); updateProductInDb(selectedProduct!.id, formData).then(() => { setIsEditOpen(false); loadData(); }); } : handleAddProduct} className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Désignation</label>
                  <input type="text" required className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-50 font-medium" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="Nom du produit..." />
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Prix d'Achat (DH)</label>
                    <input type="number" step="0.01" required className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-50 font-bold" value={formData.purchasePrice} onChange={e => setFormData({...formData, purchasePrice: Number(e.target.value)})} />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Prix de Vente (DH)</label>
                    <input type="number" step="0.01" required className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-50 font-bold text-indigo-600" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-6">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Stock Actuel</label>
                    <input type="number" required className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-50 font-bold disabled:opacity-30" disabled={formData.isOrderBased} value={formData.stock} onChange={e => setFormData({...formData, stock: Number(e.target.value)})} />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">URL Image</label>
                    <input type="text" required className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-50 text-sm" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} placeholder="https://..." />
                  </div>
                </div>
                <div className="flex items-center gap-4 bg-indigo-50/50 p-5 rounded-2xl border border-indigo-100 transition-all hover:bg-indigo-50">
                    <input type="checkbox" id="isOrderBased" className="w-6 h-6 rounded-lg text-indigo-600 focus:ring-indigo-500 cursor-pointer accent-indigo-600" checked={formData.isOrderBased} onChange={e => setFormData({...formData, isOrderBased: e.target.checked})} />
                    <label htmlFor="isOrderBased" className="text-sm font-bold text-indigo-900 cursor-pointer select-none">Produit "Sur Commande" <span className="text-[10px] font-medium opacity-60 block mt-0.5">Le stock sera marqué comme illimité</span></label>
                </div>
                <button type="submit" className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black text-lg hover:bg-slate-800 transition-all mt-6 shadow-2xl shadow-slate-900/20 active:scale-95">
                  {isEditOpen ? 'Enregistrer les modifications' : 'Ajouter à l\'inventaire'}
                </button>
             </form>
           </div>
        </div>
      )}

      {/* Add Pack Modal */}
      {isAddPackOpen && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl p-10 max-h-[90vh] overflow-y-auto animate-fade-in-scale scrollbar-hide">
             <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-black tracking-tight">Configuration de Pack</h2>
                <button onClick={() => setIsAddPackOpen(false)} className="p-3 hover:bg-slate-100 rounded-full"><XIcon className="w-6 h-6"/></button>
             </div>
             <div className="bg-amber-50 p-6 rounded-3xl border border-amber-100 mb-8 flex gap-5 items-center">
                <div className="p-3 bg-amber-100 rounded-2xl text-amber-600"><LayersIcon className="w-7 h-7"/></div>
                <p className="text-sm text-amber-800 font-bold leading-tight">Optimisez vos ventes en regroupant des produits populaires à prix préférentiel.</p>
             </div>
             <form onSubmit={handleAddPack} className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Titre du Pack</label>
                  <input type="text" required placeholder="Ex: Pack Routine Visage Hydra" className="w-full px-6 py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-amber-50 font-bold" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Produits Inclus</label>
                  <div className="border border-slate-200 rounded-[2rem] overflow-hidden mb-4 bg-white shadow-sm ring-1 ring-slate-100">
                    <div className="p-4 bg-slate-50 border-b flex items-center gap-3">
                      <SearchIcon className="w-5 h-5 text-slate-400"/>
                      <input type="text" placeholder="Chercher un produit..." className="bg-transparent text-sm w-full outline-none font-medium" value={packSearch} onChange={e => setPackSearch(e.target.value)}/>
                    </div>
                    <div className="max-h-56 overflow-y-auto p-4 space-y-2">
                      {products.filter(p => p.name.toLowerCase().includes(packSearch.toLowerCase()) && p.category !== 'pack').map(p => (
                        <button key={p.id} type="button" onClick={() => setPackItems([...packItems, { productId: p.id, productName: p.name, quantity: 1, unitCost: p.purchasePrice }])} className="flex items-center gap-4 p-3 hover:bg-indigo-50 rounded-2xl w-full text-left transition-all group">
                          <img src={p.image} className="w-12 h-12 rounded-xl object-contain bg-white shadow-sm border border-slate-100" alt="" />
                          <div className="flex-1">
                            <span className="text-sm font-bold text-slate-800 block">{p.name}</span>
                            <span className="text-[10px] font-bold text-slate-400">{p.purchasePrice.toFixed(2)} DH</span>
                          </div>
                          <div className="p-2 bg-slate-100 rounded-full text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all"><PlusIcon className="w-4 h-4"/></div>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
                {packItems.length > 0 && (
                  <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Composants sélectionnés</label>
                    {packItems.map((item, idx) => (
                      <div key={idx} className="flex items-center gap-4 bg-slate-50 p-4 rounded-2xl border border-slate-100 transition-all hover:border-slate-300">
                        <span className="flex-1 text-sm font-bold text-slate-800 truncate ml-2">{item.productName}</span>
                        <div className="flex items-center gap-3 bg-white px-3 py-1.5 rounded-xl shadow-sm border border-slate-100">
                           <span className="text-[10px] font-bold text-slate-400">Qté</span>
                           <input type="number" min="1" className="w-12 text-center text-sm font-black bg-transparent outline-none" value={item.quantity} onChange={e => { const newItems = [...packItems]; newItems[idx].quantity = Number(e.target.value); setPackItems(newItems); }} />
                        </div>
                        <button type="button" onClick={() => setPackItems(packItems.filter((_, i) => i !== idx))} className="text-rose-400 hover:text-rose-600 p-2 transition-colors"><TrashIcon className="w-5 h-5"/></button>
                      </div>
                    ))}
                  </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl shadow-slate-900/10">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] block">Coût total (Achat)</label>
                      <p className="text-2xl font-black text-white">{packSummary.cost.toFixed(2)} <span className="text-xs font-normal opacity-50">DH</span></p>
                    </div>
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] block">Prix de Vente Pack</label>
                      <div className="flex items-center gap-3">
                        <input type="number" required className="w-full bg-white/10 border border-white/10 rounded-xl px-4 py-2 font-black text-amber-400 outline-none focus:ring-2 focus:ring-amber-400/50" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                        <span className="text-amber-400 font-bold">DH</span>
                      </div>
                    </div>
                    <div className="md:col-span-2 pt-4 border-t border-white/5 flex items-center justify-between">
                       <span className="text-[10px] font-bold text-slate-500 uppercase">Marge estimée</span>
                       <span className={`text-sm font-black ${packSummary.profit >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                         {packSummary.profit > 0 ? '+' : ''}{packSummary.profit.toFixed(2)} DH
                       </span>
                    </div>
                </div>

                <button type="submit" disabled={packItems.length === 0} className="w-full py-5 bg-amber-500 text-white rounded-[2rem] font-black text-lg hover:bg-amber-600 transition-all shadow-xl shadow-amber-200 active:scale-95 disabled:opacity-30 disabled:cursor-not-allowed">
                  Finaliser et Lancer le Pack
                </button>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;

