        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[2rem] shadow-2xl p-8 max-h-[95vh] overflow-y-auto animate-fade-in-scale scrollbar-hide">
             <div className="flex justify-between items-center mb-6 border-b pb-4">
                <h2 className="text-xl font-black text-slate-800 tracking-tight">Création de Pack</h2>
                <button onClick={() => setIsAddPackOpen(false)} className="text-slate-400 hover:text-slate-600"><XIcon className="w-5 h-5"/></button>
             </div>

             <form onSubmit={handleAddPack} className="space-y-6">
                {/* Product Selection List */}
                <div className="bg-white border rounded-2xl p-4 space-y-3 shadow-sm min-h-[120px]">
                    <div className="relative mb-3">
                        <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                        <input type="text" placeholder="Ajouter des produits au pack..." className="w-full pl-9 pr-3 py-2 text-sm bg-slate-50 border-none rounded-xl outline-none" value={packSearch} onChange={e => setPackSearch(e.target.value)}/>

                        {/* Dropdown for product selection */}
                        {packSearch && (
                            <div className="absolute top-full left-0 right-0 mt-2 bg-white border rounded-xl shadow-xl z-10 max-h-48 overflow-y-auto p-1 divide-y divide-slate-50">
                                {products.filter(p => p.name.toLowerCase().includes(packSearch.toLowerCase()) && p.category !== 'pack').map(p => (
                                    <button key={p.id} type="button" onClick={() => { setPackItems([...packItems, { productId: p.id, productName: p.name, quantity: 1, unitCost: p.purchasePrice }]); setPackSearch(''); }} className="w-full flex items-center gap-3 p-3 hover:bg-indigo-50 text-left transition-colors group">
                                        <img src={p.image} className="w-8 h-8 rounded-lg object-contain bg-white shadow-sm border" alt=""/>
                                        <div className="flex-1">
                                            <p className="text-xs font-bold text-slate-800">{p.name}</p>
                                            <p className="text-[10px] text-slate-400">{p.purchasePrice} DH</p>
                                        </div>
                                        <PlusIcon className="w-4 h-4 text-slate-300 group-hover:text-indigo-600" />
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    <div className="space-y-2">
                        {packItems.map((item, idx) => (
                            <div key={idx} className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl border border-slate-100 group">
                                <div className="w-8 h-8 bg-white rounded-lg border border-slate-200 flex items-center justify-center text-[8px] font-bold text-slate-400 overflow-hidden">
                                    {products.find(p => p.id === item.productId)?.image ? (
                                        <img src={products.find(p => p.id === item.productId)?.image} className="w-full h-full object-contain" alt=""/>
                                    ) : 'IMG'}
                                </div>
                                <span className="flex-1 text-xs font-bold text-slate-700 truncate">{item.productName}</span>
                                <div className="flex items-center gap-2">
                                    <input type="number" min="1" className="w-10 text-center text-xs font-black bg-white border border-slate-200 rounded-lg p-1 outline-none" value={item.quantity} onChange={e => { const newItems = [...packItems]; newItems[idx].quantity = Number(e.target.value); setPackItems(newItems); }} />
                                    <button type="button" onClick={() => setPackItems(packItems.filter((_, i) => i !== idx))} className="text-slate-300 hover:text-rose-500 transition-colors"><TrashIcon className="w-4 h-4"/></button>
                                </div>
                            </div>
                        ))}
                        {packItems.length === 0 && (
                            <div className="py-4 text-center text-slate-300 text-[10px] font-bold uppercase tracking-widest">
                                Aucun produit sélectionné
                            </div>
                        )}
                    </div>
                </div>

                {/* Initial Stock */}
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Stock Initial</label>
                  <input type="number" placeholder="0" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-amber-100 font-bold disabled:bg-slate-100 disabled:opacity-50" disabled={formData.isOrderBased} value={formData.stock} onChange={e => setFormData({...formData, stock: Number(e.target.value)})} />
                </div>

                {/* Sur commande Checkbox */}
                <div className="flex items-center gap-3 bg-indigo-50/30 p-4 rounded-xl border border-indigo-100/50">
                    <input type="checkbox" id="pack-sur-commande" className="w-5 h-5 rounded-md text-indigo-600 focus:ring-indigo-500 cursor-pointer accent-indigo-600" checked={formData.isOrderBased} onChange={e => setFormData({...formData, isOrderBased: e.target.checked})} />
                    <label htmlFor="pack-sur-commande" className="text-sm font-black text-indigo-700 cursor-pointer select-none">Sur commande</label>
                </div>

                {/* Cost/Price Box */}
                <div className="bg-slate-50 border border-slate-200 rounded-2xl p-6 grid grid-cols-2 gap-x-8 gap-y-4">
                    <div className="space-y-1">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Coût de revient</label>
                        <p className="text-lg font-black text-slate-800">{packSummary.cost.toFixed(2)} DH</p>
                    </div>
                    <div className="space-y-1 text-right">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block">Prix Vente Pack</label>
                        <div className="flex items-center justify-end gap-2">
                            <input type="number" step="0.01" className="w-24 text-right bg-white border border-slate-200 rounded-lg px-3 py-1.5 font-black text-amber-500 outline-none focus:ring-2 focus:ring-amber-200" value={formData.salePrice} onChange={e => setFormData({...formData, salePrice: Number(e.target.value)})} />
                            <span className="text-xs font-bold text-amber-600">DH</span>
                        </div>
                        <p className={`text-[10px] font-bold ${packSummary.profit >= 0 ? 'text-emerald-500' : 'text-rose-500'}`}>Marge: {packSummary.profit.toFixed(2)} DH</p>
                    </div>
                </div>

                {/* Image & Description */}
                <div className="space-y-4 pt-2">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Image & Description</h3>
                    <div>
                        <input type="text" placeholder="URL Image" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-slate-100 text-sm" value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} />
                    </div>
                    <div>
                        <textarea rows={3} placeholder="Description marketing..." className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-slate-100 text-sm resize-none" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                    </div>
                </div>

                <button type="submit" disabled={packItems.length === 0} className="w-full py-5 bg-amber-400 text-white rounded-2xl font-black text-lg hover:bg-amber-500 transition-all shadow-xl shadow-amber-900/10 active:scale-95 disabled:opacity-30 disabled:cursor-not-allowed">
                  Lancer le Pack
                </button>
             </form>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;

import React, { useState, useEffect, useMemo } from 'react';
