      // Handle both Firestore Timestamps and raw numbers
      let dateValue = data.date;
      if (dateValue && typeof dateValue.toMillis === 'function') {
        dateValue = dateValue.toMillis();
      }

      return {
        id: doc.id,
        ...data,
