  if (updates.salePrice !== undefined) cleanUpdates.salePrice = cleanNum(updates.salePrice);
  if (updates.purchasePrice !== undefined) cleanUpdates.purchasePrice = cleanNum(updates.purchasePrice);
  if (updates.stock !== undefined) {
