export const addSaleToDb = async (sale: Omit<Sale, 'id'>, currentStock: number) => {
  // Enregistrer la vente dans Firestore
  const saleRef = await addDoc(collection(db, SALES_COL), {
    ...sale,
    date: Date.now() // Use local time for better client-side ordering
  });

  // Mettre à jour le stock du produit
  const productRef = doc(db, PRODUCTS_COL, sale.productId);

  // Note: We only decrement stock if it's not strictly "sur commande" logic 
  // though typically we decrement availableStock and let it go negative if needed 
  // or handle infinity elsewhere.
  await updateDoc(productRef, {
    availableStock: cleanNum(currentStock - sale.quantity),
    stock: cleanNum(currentStock - sale.quantity),
    // Increment total sold (simplified)
    totalSold: cleanNum((sale as any).totalSold || 0) + sale.quantity
  });

  return saleRef.id;
};

