      'Adresse': orderData.address,
      'Ville': orderData.city,
      'Total (DH)': formattedTotal,
      'Produits': itemsString,
    };
    try {
      await fetch(GOOGLE_SHEET_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
            'Content-Type': 'text/plain;charset=utf-8',
