const ShoppingCartIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z" /></svg>;
const EditIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>;
const TrashIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const DollarSignIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M12 16V15" /></svg>;
const TrendingUpIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>;
const BoxIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10l8 4 8-4V7l-8-4-8 4zm8-4v10m8-10l-8 4m0 0L4 7" /></svg>;
const XIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>;
const AlertCircleIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const BellIcon = ({ className }: { className?: string }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>;

const StatCard = ({ title, value, icon, color, trend, isPositive }: { title: string, value: string, icon: any, color: string, trend: string, isPositive: boolean }) => {
  const colorMap: any = {
    indigo: 'bg-indigo-600 shadow-indigo-200',
    emerald: 'bg-emerald-500 shadow-emerald-200',
    blue: 'bg-blue-500 shadow-blue-200',
    amber: 'bg-amber-500 shadow-amber-200',
  };
  return (
    <div className="bg-white p-6 rounded-3xl border border-slate-200/60 shadow-sm flex flex-col justify-between hover:shadow-xl transition-all duration-300 group">
      <div className="flex justify-between items-start mb-4">
        <div className={`p-4 rounded-2xl text-white transition-transform group-hover:scale-110 ${colorMap[color] || 'bg-slate-900'}`}>{icon}</div>
        <div className={`text-[10px] font-bold px-2.5 py-1 rounded-full border ${isPositive ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-rose-50 text-rose-500 border-rose-100'}`}>
          {trend}
        </div>
      </div>
      <div>
        <p className="text-slate-400 text-[10px] font-bold uppercase tracking-[0.1em] mb-1">{title}</p>
        <p className="text-2xl font-black text-slate-800">{value}</p>
      </div>
    </div>
  );
};

const AdminPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [search, setSearch] = useState('');
  const [currentTab, setCurrentTab] = useState<'dashboard' | 'inventory' | 'sales' | 'orders' | 'packs'>('dashboard');

  // Modals
  const [isAddProductOpen, setIsAddProductOpen] = useState(false);
  const [isAddPackOpen, setIsAddPackOpen] = useState(false);
  const [isSellOpen, setIsSellOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [isDeleteConfirmOpen, setIsDeleteConfirmOpen] = useState(false);

  // Selection
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [sellQty, setSellQty] = useState(1);
  const [packItems, setPackItems] = useState<PackItem[]>([]);
  const [packSearch, setPackSearch] = useState('');

  const initialForm = { name: '', description: '', image: '', purchasePrice: 0, salePrice: 0, stock: 0, isOrderBased: false, category: 'simple' as any };
  const [formData, setFormData] = useState(initialForm);

  const navigate = useNavigate();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      if (!currentUser) navigate('/login');
      else {
        setUser(currentUser);
        loadData();
      }
    });
    return () => unsubscribe();
  }, [navigate]);

  useEffect(() => {
    if (user) loadData();
  }, [currentTab, user]);

  const loadData = async () => {
    try {
      const [p, s, o] = await Promise.all([getProducts(), getSales(), getOrders()]);
      setProducts(p);
      setSales(s.sort((a,b) => b.date - a.date));
      setOrders(o);
    } catch (e: any) {
      console.error("Failed to load admin data:", e);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => signOut(auth).then(() => navigate('/login'));

  const stats: Stats = useMemo(() => {
    const revenue = sales.reduce((acc, s) => acc + (s.totalPrice || 0), 0);
    const profit = sales.reduce((acc, s) => acc + (s.profit || 0), 0);
    const totalSold = sales.reduce((acc, s) => acc + (s.quantity || 0), 0);
    const stockValue = products.reduce((acc, p) => acc + ((p.purchasePrice || 0) * (p.stock || 0)), 0);
    return { revenue, profit, totalSold, stockValue };
  }, [products, sales]);

  const handleValidateOrder = async (order: Order) => {
    try {
      // Logic to convert order to sales
      for (const item of order.items) {
        const prod = products.find(p => p.id === item.id);
        const saleData = {
          productId: item.id,
          productName: item.name,
          quantity: item.quantity,
          totalPrice: item.price * item.quantity,
          profit: (item.price - (prod?.purchasePrice || 0)) * item.quantity,
          date: Date.now()
        };
        await addSaleToDb(saleData);
      }
      await deleteOrderFromDb(order.id);
      loadData();
    } catch (err: any) {
      alert("Erreur lors de la validation: " + err.message);
    }
  };

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await addProductToDb({ ...formData, totalSold: 0 });
      setIsAddProductOpen(false);
      loadData();
    } catch (err: any) { alert("Erreur: " + err.message); }
  };

  const handleSell = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProduct) return;
    try {
      const saleData = {
        productId: selectedProduct.id,
        productName: selectedProduct.name,
        quantity: sellQty,
        totalPrice: sellQty * Number(selectedProduct.salePrice),
        profit: sellQty * (Number(selectedProduct.salePrice) - Number(selectedProduct.purchasePrice || 0)),
        date: Date.now()
      };
      await addSaleToDb(saleData);
      setIsSellOpen(false);
      loadData();
    } catch (err: any) { alert(err.message); }
  };

  const confirmDelete = async () => {
    if (productToDelete) {
      try {
        await deleteProductFromDb(productToDelete.id);
        setIsDeleteConfirmOpen(false);
        setProductToDelete(null);
        loadData();
      } catch (err: any) { alert(err.message); }
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center bg-slate-50"><Spinner /></div>;

  return (
    <div className="flex h-screen bg-[#F8FAFC] font-sans text-slate-900 overflow-hidden fixed inset-0 z-[100]">

      <aside className="hidden md:flex flex-col w-20 lg:w-72 bg-white border-r border-slate-200 transition-all shadow-sm">
        <div className="h-20 flex items-center px-8 border-b border-slate-100 shrink-0">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl">M</div>
          <span className="font-bold text-xl text-slate-800 ml-4 hidden lg:block">Mercadona Admin</span>
        </div>

        <div className="flex-1 py-8 px-4 space-y-2 overflow-y-auto">
          {[
            { id: 'dashboard', label: 'Tableau de bord', icon: <LayoutIcon className="w-5 h-5" /> },
            { id: 'orders', label: 'Commandes Client', icon: <BellIcon className="w-5 h-5" />, badge: orders.length },
            { id: 'inventory', label: 'Stock / Produits', icon: <PackageIcon className="w-5 h-5" /> },
            { id: 'sales', label: 'Ventes', icon: <HistoryIcon className="w-5 h-5" /> },
          ].map((item) => (
            <button 
              key={item.id}
              onClick={() => setCurrentTab(item.id as any)}
              className={`w-full flex items-center justify-between px-4 py-3.5 rounded-xl font-medium transition-all group ${currentTab === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-3">
                {item.icon}
                <span className="hidden lg:block">{item.label}</span>
              </div>
              {item.badge && item.badge > 0 && (
                <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${currentTab === item.id ? 'bg-white text-indigo-600' : 'bg-rose-500 text-white'}`}>
                  {item.badge}
                </span>
              )}
            </button>
          ))}
        </div>

        <div className="p-4 border-t border-slate-100">
          <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 text-rose-600 hover:bg-rose-50 rounded-xl font-medium">
            <XIcon className="w-5 h-5" />
            <span className="hidden lg:block">Déconnexion</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full overflow-hidden">
        <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-8 z-20">
          <h2 className="text-xl font-black text-slate-800 capitalize">{currentTab}</h2>
          <div className="flex items-center gap-4">
             <div className="relative hidden sm:block">
                <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                <input type="text" placeholder="Rechercher..." value={search} onChange={e => setSearch(e.target.value)} className="pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-100 outline-none" />
             </div>
             <button onClick={() => setIsAddProductOpen(true)} className="flex items-center gap-2 px-5 py-2.5 bg-slate-900 text-white text-sm font-bold rounded-xl shadow-lg hover:bg-slate-800 transition-all">
                <PlusIcon className="w-4 h-4" />
                <span className="hidden sm:inline">Ajouter Produit</span>
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          {currentTab === 'dashboard' && (
            <div className="animate-fade-in space-y-8">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard title="Revenu" value={`${stats.revenue.toLocaleString()} DH`} icon={<DollarSignIcon className="w-6 h-6"/>} color="indigo" trend="+12%" isPositive={true}/>
                <StatCard title="Bénéfice" value={`${stats.profit.toLocaleString()} DH`} icon={<TrendingUpIcon className="w-6 h-6"/>} color="emerald" trend="+8%" isPositive={true} />
                <StatCard title="Ventes" value={`${stats.totalSold}`} icon={<ShoppingCartIcon className="w-6 h-6"/>} color="blue" trend="Live" isPositive={true} />
                <StatCard title="Stock" value={`${stats.stockValue.toLocaleString()} DH`} icon={<BoxIcon className="w-6 h-6"/>} color="amber" trend="-2%" isPositive={false} />
              </div>

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm">
                  <h3 className="text-lg font-bold mb-6">Commandes en attente</h3>
                  <div className="space-y-4">
                    {orders.slice(0, 3).map(order => (
                      <div key={order.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-200 flex justify-between items-center">
                        <div>
                          <p className="font-bold text-sm">{order.name}</p>
                          <p className="text-xs text-slate-500">{order.city} - {order.total.toFixed(2)} DH</p>
                        </div>
                        <button onClick={() => setCurrentTab('orders')} className="text-indigo-600 text-xs font-bold hover:underline">Voir détails</button>
                      </div>
                    ))}
                    {orders.length === 0 && <p className="text-center text-slate-400 py-4 text-sm font-medium">Aucune commande en attente.</p>}
                  </div>
                </div>
                <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm">
                   <h3 className="text-lg font-bold mb-6">Alertes Stock</h3>
                   <div className="space-y-4">
                      {products.filter(p => !p.isOrderBased && p.stock < 10).slice(0, 3).map(p => (
                        <div key={p.id} className="flex items-center gap-4 p-4 bg-rose-50 rounded-2xl border border-rose-100">
                           <img src={p.image} className="w-10 h-10 rounded-lg object-contain bg-white" alt=""/>
                           <div className="flex-1 min-w-0">
                             <p className="text-sm font-bold text-slate-800 truncate">{p.name}</p>
                             <p className="text-[10px] font-bold text-rose-500">{p.stock} restants</p>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            </div>
          )}

          {currentTab === 'orders' && (
            <div className="animate-fade-in space-y-6">
              {orders.map(order => (
                <div key={order.id} className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm hover:shadow-md transition-all">
                  <div className="flex flex-col md:flex-row justify-between gap-6">
                    <div className="flex-1">
                      <div className="flex items-center gap-3 mb-4">
                         <span className="px-3 py-1 bg-amber-100 text-amber-700 rounded-full text-[10px] font-black uppercase">En attente</span>
                         <span className="text-xs text-slate-400 font-bold">{new Date(order.createdAt as any).toLocaleString()}</span>
                      </div>
                      <h4 className="text-lg font-bold text-slate-800">{order.name}</h4>
                      <p className="text-sm text-slate-500 mt-1">{order.phone} • {order.address}, {order.city}</p>

                      <div className="mt-6 space-y-2">
                        {order.items.map((item, idx) => (
                          <div key={idx} className="flex justify-between items-center py-2 border-b border-slate-50">
                            <span className="text-sm font-medium">{item.name} <span className="text-indigo-600 font-bold ml-1">x{item.quantity}</span></span>
                            <span className="text-sm font-bold">{(item.price * item.quantity).toFixed(2)} DH</span>
                          </div>
                        ))}
                      </div>
                    </div>
                    <div className="md:w-64 flex flex-col justify-between items-end border-l border-slate-100 pl-6">
                       <div className="text-right">
                          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Commande</p>
                          <p className="text-2xl font-black text-slate-800">{order.total.toFixed(2)} DH</p>
                       </div>
                       <div className="flex gap-3 mt-8 w-full">
                          <button onClick={() => deleteOrderFromDb(order.id).then(loadData)} className="flex-1 py-3 text-rose-600 bg-rose-50 rounded-xl text-xs font-bold hover:bg-rose-100">Rejeter</button>
                          <button onClick={() => handleValidateOrder(order)} className="flex-1 py-3 text-white bg-indigo-600 rounded-xl text-xs font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100">Valider</button>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
              {orders.length === 0 && (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                   <BellIcon className="w-12 h-12 mb-4 opacity-20" />
                   <p className="font-bold">Aucune nouvelle commande.</p>
                </div>
              )}
            </div>
          )}

          {currentTab === 'inventory' && (
            <div className="animate-fade-in bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                    <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      <th className="px-8 py-4">Produit</th>
                      <th className="px-8 py-4">Prix</th>
                      <th className="px-8 py-4">Stock</th>
                      <th className="px-8 py-4 text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(product => (
                      <tr key={product.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-8 py-4 flex items-center gap-4">
                           <img src={product.image} className="w-12 h-12 rounded-xl object-contain bg-white border border-slate-100" alt=""/>
                           <span className="font-bold text-sm text-slate-800">{product.name}</span>
                        </td>
                        <td className="px-8 py-4 text-sm font-bold text-indigo-600">{product.salePrice.toFixed(2)} DH</td>
                        <td className="px-8 py-4">
                           <span className={`px-2.5 py-1 rounded-lg text-xs font-black ${product.stock > 10 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                             {product.isOrderBased ? '∞' : product.stock}
                           </span>
                        </td>
                        <td className="px-8 py-4 text-right space-x-2">
                           <button onClick={() => { setSelectedProduct(product); setIsEditOpen(true); setFormData({...product} as any); }} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors"><EditIcon className="w-5 h-5"/></button>
                           <button onClick={() => { setProductToDelete(product); setIsDeleteConfirmOpen(true); }} className="p-2 text-slate-400 hover:text-rose-600 transition-colors"><TrashIcon className="w-5 h-5"/></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
               </table>
            </div>
          )}

          {currentTab === 'sales' && (
            <div className="animate-fade-in bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-sm">
               <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                    <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                      <th className="px-8 py-4">Produit</th>
                      <th className="px-8 py-4">Date</th>
                      <th className="px-8 py-4">Qté</th>
                      <th className="px-8 py-4 text-right">Total</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {sales.map(sale => (
                      <tr key={sale.id} className="hover:bg-slate-50/50">
                        <td className="px-8 py-4 font-bold text-sm text-slate-800">{sale.productName}</td>
                        <td className="px-8 py-4 text-xs text-slate-500">{new Date(sale.date).toLocaleString()}</td>
                        <td className="px-8 py-4 text-sm font-bold">{sale.quantity}</td>
