import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import { useUI } from '../hooks/useUI';
import { useCart } from '../hooks/useCart';
import { Order } from '../types';
import { getDeliveryFee, getCityList } from '../utils/shippingData';
import { addOrderToDb, updateProductInDb } from '../services/store';
import { increment } from 'firebase/firestore';

const GOOGLE_SHEET_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzm0RVh06-qE7x7r6J0NWdwo8EOj2O91RILusXZ30g5YD-5kVN-GoLze-seZAFvtpDMQw/exec';

const CheckoutModal: React.FC = () => {
  const { isCheckoutOpen, closeCheckout } = useUI();
  const { cartItems, cartTotal, clearCart } = useCart();
  const [formData, setFormData] = useState({ name: '', phone: '', address: '', city: '' });
  const [deliveryFee, setDeliveryFee] = useState(0);
  const [error, setError] = useState('');
  const [isOrderSuccess, setIsOrderSuccess] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const cityList = getCityList();

  useEffect(() => {
    if (formData.city && formData.city.trim() !== '') {
        const fee = getDeliveryFee(formData.city);
        setDeliveryFee(fee);
    } else {
        setDeliveryFee(0);
    }
  }, [formData.city]);

  const finalTotal = cartTotal + deliveryFee;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.id]: e.target.value });
  };

  const handleClose = () => {
    closeCheckout();
    setTimeout(() => {
        setIsOrderSuccess(false);
        setFormData({ name: '', phone: '', address: '', city: '' });
        setError('');
        setDeliveryFee(0);
        setIsSubmitting(false);
    }, 300);
  };

  const logOrderToSheet = async (orderData: Omit<Order, 'id' | 'createdAt'>) => {
    if (!GOOGLE_SHEET_WEB_APP_URL) return;
    const itemsString = orderData.items.map(item => `${item.name} (x${item.quantity})`).join(', ');
    const formattedTotal = `${cartTotal.toFixed(2)}dh + ${deliveryFee.toFixed(2)}dh`;

    const rowData = {
      'Date': new Date().toLocaleString('fr-FR'),
      'Nom Client': orderData.name,
      'Téléphone': orderData.phone,
      'Adresse': orderData.address,
      'Ville': orderData.city,
      'Total (DH)': formattedTotal,
      'Produits': itemsString,
    };
    try {
      await fetch(GOOGLE_SHEET_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify(rowData),
      });
    } catch (sheetError) {
      console.warn("Sheet logging failed:", sheetError);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cartItems.length === 0) return setError('Votre panier est vide.');

    setIsSubmitting(true);
    setError('');

    const orderData: Omit<Order, 'id'> = {
        ...formData,
        items: cartItems.map(({ id, name, salePrice, quantity }) => ({ id, name, price: salePrice, quantity })),
        total: finalTotal,
        status: 'pending'
    };

    try {
        // 1. Send to Google Sheet (Backup & Primary Notification)
        await logOrderToSheet(orderData);

        // 2. Save Order to Firebase (The new "Logical" way to handle guest permissions)
        await addOrderToDb(orderData);

        // 3. Optimistic Stock Update (If permissions allow)
        try {
          for (const item of cartItems) {
            if (!item.isOrderBased) {
              await updateProductInDb(item.id, { availableStock: increment(-item.quantity) } as any);
            }
          }
        } catch (stockErr) {
          console.warn("Optimistic stock update blocked by permissions. Stock will be updated upon admin validation.");
        }

        clearCart();
        setIsOrderSuccess(true);
    } catch (err: any) {
        setError("Une erreur est survenue. Nous avons bien reçu votre commande via Google Sheets, mais l'enregistrement interne a échoué. Ne vous inquiétez pas, nous vous contacterons.");
        console.error(err);
        // Special case: if it reached here, we still show success if sheet was likely sent
        if (err.message.includes("permission")) {
           clearCart();
           setIsOrderSuccess(true);
        }
    } finally {
        setIsSubmitting(false);
    }
  };

  if (!isCheckoutOpen) return null;

  return (
    <Modal isOpen={isCheckoutOpen} onClose={handleClose}>
        {isOrderSuccess ? (
            <div className="flex flex-col items-center justify-center h-full p-10 text-center bg-white">
                <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center mb-6">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                    </svg>
                </div>
                <h2 className="text-2xl font-serif font-bold text-slate-800">Merci pour votre confiance !</h2>
                <p className="mt-4 text-secondary text-sm leading-relaxed max-w-xs">
                    Votre commande est bien reçue. Notre équipe vous contactera très prochainement pour confirmer la livraison.
                </p>
                <button onClick={handleClose} className="mt-10 w-full bg-slate-900 text-white font-bold py-4 rounded-xl hover:bg-slate-800 transition-all shadow-lg active:scale-95">
                    RETOUR À LA BOUTIQUE
                </button>
            </div>
        ) : (
        <>
            <div className="flex justify-between items-center p-6 border-b border-gray-100">
                <h2 className="text-lg font-serif font-semibold text-primary">Finaliser ma commande</h2>
                <button type="button" onClick={handleClose} className="text-gray-400 hover:text-primary transition-colors">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-grow flex flex-col overflow-hidden">
                <div className="p-6 overflow-y-auto space-y-6">
                    <div className="space-y-4">
                        <div className="flex items-center gap-2 mb-2">
                           <div className="w-1 h-5 bg-indigo-600 rounded-full"></div>
                           <h3 className="font-black text-xs uppercase tracking-widest text-slate-400">Vos informations</h3>
                        </div>

                        <input type="text" id="name" required placeholder="Nom et Prénom" value={formData.name} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all" />
                        <input type="tel" id="phone" required placeholder="Téléphone" value={formData.phone} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all" />

                        <div className="flex items-center gap-2 mb-2 pt-2">
                           <div className="w-1 h-5 bg-indigo-600 rounded-full"></div>
                           <h3 className="font-black text-xs uppercase tracking-widest text-slate-400">Adresse de livraison</h3>
                        </div>

                        <input type="text" id="address" required placeholder="Adresse (Quartier, N°, etc.)" value={formData.address} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all" />
                        <div className="relative">
                            <input type="text" id="city" list="city-options" required placeholder="Ville" value={formData.city} onChange={handleChange} className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all" />
                            <datalist id="city-options">
                                {cityList.map((city, index) => (
                                    <option key={index} value={city.charAt(0).toUpperCase() + city.slice(1)} />
                                ))}
                            </datalist>
                        </div>
                    </div>

                    {error && (
                        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl">
                            <p className="text-rose-600 text-xs font-bold leading-relaxed">{error}</p>
                        </div>
                    )}

                    <div className="pt-4 border-t border-gray-100 space-y-3">
                        <div className="flex justify-between text-sm text-secondary"><span>Articles</span><span>{cartTotal.toFixed(2)} DH</span></div>
                        <div className="flex justify-between text-sm text-secondary"><span>Livraison</span><span>{deliveryFee > 0 ? `${deliveryFee.toFixed(2)} DH` : 'Gratuite'}</span></div>
                        <div className="flex justify-between text-lg font-black text-primary"><span>Total à payer</span><span>{finalTotal.toFixed(2)} DH</span></div>
                    </div>
                </div>

                <div className="p-6 border-t border-gray-100 mt-auto bg-slate-50">
                    <button type="submit" disabled={cartItems.length === 0 || isSubmitting} className="w-full bg-slate-900 text-white font-black py-4 rounded-xl hover:bg-slate-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-xl active:scale-95">
                        {isSubmitting ? 'Traitement en cours...' : 'CONFIRMER MA COMMANDE'}
                    </button>
                    <p className="text-[10px] text-center text-slate-400 font-bold uppercase mt-4 tracking-widest">Paiement Cash à la Livraison</p>
                </div>
            </form>
        </>
        )}
    </Modal>
  );
};

