import { 
  collection, 
  getDocs, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy, 
  serverTimestamp,
  increment,
  writeBatch
} from 'firebase/firestore';
import { db } from './firebase';
import { Product, Sale, Order } from '../types';

const PRODUCTS_COL = 'products';
const SALES_COL = 'sales';
const ORDERS_COL = 'orders';

const cleanNum = (val: any): number => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

export const getProducts = async (): Promise<Product[]> => {
  try {
    const q = query(collection(db, PRODUCTS_COL), orderBy('name'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      const aStock = data.availableStock ?? data.stock ?? 0;
      return {
        id: doc.id,
        ...data,
        purchasePrice: cleanNum(data.purchasePrice),
        salePrice: cleanNum(data.salePrice ?? data.price),
        stock: cleanNum(data.stock),
        availableStock: cleanNum(aStock),
        totalSold: cleanNum(data.totalSold),
        category: data.category || 'simple',
        isOrderBased: !!data.isOrderBased
      } as Product;
    });
  } catch (error) {
    console.error("Error fetching products:", error);
    return [];
  }
};

export const getSales = async (): Promise<Sale[]> => {
  try {
    const snap = await getDocs(collection(db, SALES_COL));
    return snap.docs.map(doc => {
      const data = doc.data();
      let dateValue = data.date;
      if (dateValue && typeof dateValue.toMillis === 'function') dateValue = dateValue.toMillis();
      return {
        id: doc.id,
        ...data,
        date: dateValue || Date.now()
      } as Sale;
    });
  } catch (error) {
    return [];
  }
};

export const getOrders = async (): Promise<Order[]> => {
  try {
    const q = query(collection(db, ORDERS_COL), orderBy('createdAt', 'desc'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      let dateValue = data.createdAt;
      if (dateValue && typeof dateValue.toMillis === 'function') dateValue = dateValue.toMillis();
      return { id: doc.id, ...data, createdAt: dateValue || Date.now() } as any;
    });
  } catch (error) {
    return [];
  }
};

/**
 * GUEST ACTION: Creating an order.
 * This should be the ONLY write action allowed for public/guest users.
 */
export const addOrderToDb = async (order: Omit<Order, 'id' | 'status' | 'createdAt'>) => {
  return await addDoc(collection(db, ORDERS_COL), {
    ...order,
    status: 'pending',
    createdAt: serverTimestamp()
  });
};

/**
 * ADMIN ACTION: Validate Order & Update Stock.
 * Uses a Batch to ensure atomicity (all updates succeed or none do).
 */
export const validateOrderAndProcessStock = async (order: Order) => {
  const batch = writeBatch(db);

  for (const item of order.items) {
    const productRef = doc(db, PRODUCTS_COL, item.id);
    const saleRef = doc(collection(db, SALES_COL));

    // 1. Log the Sale
    batch.set(saleRef, {
      productId: item.id,
      productName: item.name,
      quantity: item.quantity,
      totalPrice: item.price * item.quantity,
      profit: (item.price - item.purchasePriceAtTime) * item.quantity,
      date: Date.now()
    });

    // 2. Atomic Stock Decrement
    batch.update(productRef, {
      availableStock: increment(-item.quantity),
      stock: increment(-item.quantity),
      totalSold: increment(item.quantity)
    });
  }

  // 3. Delete the Order after successful processing
  const orderRef = doc(db, ORDERS_COL, order.id);
  batch.delete(orderRef);

  await batch.commit();
};

export const deleteOrderFromDb = async (id: string) => {
  await deleteDoc(doc(db, ORDERS_COL, id));
};

export const addProductToDb = async (product: Omit<Product, 'id'>) => {
  const data = {
    ...product,
    availableStock: cleanNum(product.stock),
    initialStock: cleanNum(product.stock),
    totalSold: 0,
    createdAt: serverTimestamp()
  };
  return await addDoc(collection(db, PRODUCTS_COL), data);
};

export const updateProductInDb = async (id: string, updates: Partial<Product>) => {
  const docRef = doc(db, PRODUCTS_COL, id);
  if (updates.stock !== undefined) {
    (updates as any).availableStock = cleanNum(updates.stock);
  }
  await updateDoc(docRef, updates);
};

export const deleteProductFromDb = async (id: string) => {
  await deleteDoc(doc(db, PRODUCTS_COL, id));
};

import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import { useUI } from '../hooks/useUI';
import { useCart } from '../hooks/useCart';
import { addOrderToDb } from '../services/store';
import { getDeliveryFee, getCityList } from '../utils/shippingData';

const GOOGLE_SHEET_URL = 'https://script.google.com/macros/s/AKfycbzm0RVh06-qE7x7r6J0NWdwo8EOj2O91RILusXZ30g5YD-5kVN-GoLze-seZAFvtpDMQw/exec';

const CheckoutModal: React.FC = () => {
  const { isCheckoutOpen, closeCheckout } = useUI();
  const { cartItems, cartTotal, clearCart } = useCart();
  const [formData, setFormData] = useState({ name: '', phone: '', address: '', city: '' });
  const [deliveryFee, setDeliveryFee] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    setDeliveryFee(formData.city ? getDeliveryFee(formData.city) : 0);
  }, [formData.city]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (cartItems.length === 0) return;
    setIsSubmitting(true);
    setError('');

    const orderPayload = {
      ...formData,
      items: cartItems.map(item => ({
        id: item.id,
        name: item.name,
        price: item.salePrice,
        quantity: item.quantity,
        purchasePriceAtTime: item.purchasePrice || 0
      })),
      total: cartTotal + deliveryFee
    };

    try {
      // 1. Permanent Log (Google Sheets)
      await fetch(GOOGLE_SHEET_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify(orderPayload)
      });

      // 2. Firestore Order (Fixed: No stock update here, so no permission error)
      await addOrderToDb(orderPayload);

      setIsSuccess(true);
      clearCart();
    } catch (err: any) {
      setError("Erreur lors de l'enregistrement. Nous avons reçu votre commande, nous vous contacterons.");
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isCheckoutOpen) return null;

  return (
    <Modal isOpen={isCheckoutOpen} onClose={closeCheckout}>
      {isSuccess ? (
        <div className="p-10 text-center animate-fade-in-scale">
