import { 
  collection, 
  getDocs, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy, 
  serverTimestamp,
  increment,
  writeBatch,
  getDoc
} from 'firebase/firestore';
import { db } from './firebase';
import { Product, Sale, Order } from '../types';

const PRODUCTS_COL = 'products';
const SALES_COL = 'sales';
const ORDERS_COL = 'orders';

const cleanNum = (val: any): number => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

export const getProducts = async (): Promise<Product[]> => {
  try {
    const q = query(collection(db, PRODUCTS_COL), orderBy('name'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      return {
        id: doc.id,
        ...data,
        purchasePrice: cleanNum(data.purchasePrice),
        salePrice: cleanNum(data.salePrice),
        stock: cleanNum(data.stock),
        availableStock: cleanNum(data.availableStock ?? data.stock),
        totalSold: cleanNum(data.totalSold)
      } as Product;
    });
  } catch (error) {
    console.error("Fetch products failed:", error);
    return [];
  }
};

export const getOrders = async (): Promise<Order[]> => {
  try {
    const q = query(collection(db, ORDERS_COL), orderBy('createdAt', 'desc'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      let dateValue = data.createdAt;
      if (dateValue && typeof dateValue.toMillis === 'function') dateValue = dateValue.toMillis();
      return { id: doc.id, ...data, createdAt: dateValue || Date.now() } as any;
    });
  } catch (error) {
    return [];
  }
};

export const addOrderToDb = async (order: Omit<Order, 'id' | 'status' | 'createdAt'>) => {
  return await addDoc(collection(db, ORDERS_COL), {
    ...order,
    status: 'pending',
    createdAt: serverTimestamp()
  });
};

export const validateOrderAndProcessStock = async (order: Order) => {
  const batch = writeBatch(db);

  for (const item of order.items) {
    const productRef = doc(db, PRODUCTS_COL, item.id);
    const saleRef = doc(collection(db, SALES_COL));

    // Vérification de sécurité pour éviter le stock négatif
    const pSnap = await getDoc(productRef);
    if (pSnap.exists()) {
      const currentStock = pSnap.data().stock || 0;
      if (currentStock < item.quantity && !pSnap.data().isOrderBased) {
        throw new Error(`Stock insuffisant pour ${item.name}`);
      }
    }

    batch.set(saleRef, {
      productId: item.id,
      productName: item.name,
      quantity: item.quantity,
      totalPrice: item.price * item.quantity,
      profit: (item.price - item.purchasePriceAtTime) * item.quantity,
      date: Date.now()
    });

    batch.update(productRef, {
      availableStock: increment(-item.quantity),
      stock: increment(-item.quantity),
      totalSold: increment(item.quantity)
    });
  }

  batch.delete(doc(db, ORDERS_COL, order.id));
  await batch.commit();
};

export const addProductToDb = async (product: Omit<Product, 'id'>) => {
  const data = {
    ...product,
    availableStock: cleanNum(product.stock),
    initialStock: cleanNum(product.stock),
    totalSold: 0,
    createdAt: serverTimestamp()
  };
  return await addDoc(collection(db, PRODUCTS_COL), data);
};

export const updateProductInDb = async (id: string, updates: Partial<Product>) => {
  const docRef = doc(db, PRODUCTS_COL, id);
  await updateDoc(docRef, updates);
};

export const deleteProductFromDb = async (id: string) => {
  await deleteDoc(doc(db, PRODUCTS_COL, id));
};

export const getSales = async (): Promise<Sale[]> => {
  try {
    const snap = await getDocs(collection(db, SALES_COL));
    return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Sale));
  } catch (error) {
    return [];
  }
};

