  const navigate = useNavigate();

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (u) => {
      if (!u) navigate('/login');
      else loadData();
    });
    return unsub;
  }, [navigate]);

  const loadData = async () => {
    setLoading(true);
    const [p, s, o] = await Promise.all([getProducts(), getSales(), getOrders()]);
    setProducts(p);
    setSales(s);
    setOrders(o);
    setLoading(false);
  };

  const stats = useMemo(() => ({
    revenue: sales.reduce((acc, s) => acc + (s.totalPrice || 0), 0),
    profit: sales.reduce((acc, s) => acc + (s.profit || 0), 0),
    totalSold: sales.reduce((acc, s) => acc + (s.quantity || 0), 0),
    stockValue: products.reduce((acc, p) => acc + ((p.purchasePrice || 0) * (p.stock || 0)), 0),
  }), [sales, products]);

  const handleAddProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await addProductToDb(newProduct as Omit<Product, 'id'>);
      setIsAddModalOpen(false);
      loadData();
    } catch (err: any) { alert(err.message); }
  };

  if (loading) return <div className="h-screen flex items-center justify-center bg-slate-50"><Spinner /></div>;

  return (
    <div className="flex h-screen bg-[#F8FAFC] font-sans text-slate-900 overflow-hidden fixed inset-0 z-[100]">
      {/* Sidebar Moderne */}
      <aside className="w-72 bg-white border-r border-slate-200 flex flex-col shadow-sm">
        <div className="p-8 border-b border-slate-100">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-black rounded-xl flex items-center justify-center text-white font-bold">M</div>
            <span className="font-black text-xl tracking-tighter">MERCADONA</span>
          </div>
        </div>

        <nav className="flex-1 p-6 space-y-2">
          {[
            { id: 'dashboard', label: 'Dashboard', icon: '📊' },
            { id: 'orders', label: 'Commandes', icon: '🔔', badge: orders.length },
            { id: 'inventory', label: 'Inventaire', icon: '📦' },
            { id: 'sales', label: 'Historique', icon: '📜' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setCurrentTab(tab.id as any)}
              className={`w-full flex items-center justify-between p-4 rounded-2xl transition-all font-bold text-sm ${currentTab === tab.id ? 'bg-black text-white shadow-xl scale-[1.02]' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-4">
                <span>{tab.icon}</span>
                {tab.label}
              </div>
              {tab.badge ? <span className="bg-rose-500 text-white text-[10px] px-2 py-0.5 rounded-full">{tab.badge}</span> : null}
            </button>
          ))}
        </nav>

        <div className="p-6 border-t border-slate-100">
          <button onClick={() => signOut(auth)} className="w-full p-4 text-rose-500 font-bold hover:bg-rose-50 rounded-2xl transition-colors">Déconnexion</button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-24 bg-white/80 backdrop-blur-md border-b border-slate-200 flex items-center justify-between px-10">
          <h1 className="text-2xl font-black capitalize tracking-tight">{currentTab}</h1>
          <button onClick={() => setIsAddModalOpen(true)} className="bg-black text-white px-6 py-3 rounded-2xl font-bold text-sm hover:scale-105 transition-transform shadow-lg">Nouveau Produit</button>
        </header>

        <div className="flex-1 overflow-y-auto p-10 space-y-10">
          {currentTab === 'dashboard' && (
            <div className="animate-fade-in-scale space-y-10">
              <div className="grid grid-cols-4 gap-6">
                {[
                  { label: 'Revenu Total', value: `${stats.revenue.toLocaleString()} DH`, color: 'bg-emerald-50 text-emerald-700' },
                  { label: 'Bénéfice Net', value: `${stats.profit.toLocaleString()} DH`, color: 'bg-indigo-50 text-indigo-700' },
                  { label: 'Articles Vendus', value: stats.totalSold, color: 'bg-amber-50 text-amber-700' },
                  { label: 'Valeur Stock', value: `${stats.stockValue.toLocaleString()} DH`, color: 'bg-slate-50 text-slate-700' }
                ].map((s, i) => (
                  <div key={i} className={`${s.color} p-8 rounded-[2rem] border border-black/5`}>
                    <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">{s.label}</p>
                    <p className="text-3xl font-black">{s.value}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {currentTab === 'orders' && (
            <div className="space-y-6">
              {orders.map(order => (
                <div key={order.id} className="bg-white border border-slate-200 p-8 rounded-[2.5rem] shadow-sm flex items-center justify-between hover:border-black transition-colors">
                  <div className="space-y-2">
                    <div className="flex items-center gap-3">
                      <span className="px-3 py-1 bg-amber-100 text-amber-700 rounded-full text-[10px] font-black uppercase">En attente</span>
                      <span className="text-xs text-slate-400 font-bold">{new Date(order.createdAt as any).toLocaleString()}</span>
                    </div>
                    <h3 className="text-xl font-black">{order.name} <span className="text-slate-400 font-normal">({order.phone})</span></h3>
                    <p className="text-sm text-slate-500 font-medium">{order.items.map(i => `${i.name} (x${i.quantity})`).join(', ')}</p>
                  </div>
                  <div className="text-right space-y-4">
                    <p className="text-2xl font-black">{order.total.toFixed(2)} DH</p>
                    <div className="flex gap-2">
                      <button onClick={() => deleteOrderFromDb(order.id).then(loadData)} className="px-6 py-2 bg-slate-100 text-slate-600 rounded-xl text-xs font-black hover:bg-slate-200">Rejeter</button>
                      <button onClick={() => validateOrderAndProcessStock(order).then(loadData)} className="px-6 py-2 bg-black text-white rounded-xl text-xs font-black hover:bg-slate-800 shadow-xl shadow-black/10">Valider</button>
                    </div>
                  </div>
                </div>
              ))}
              {orders.length === 0 && <div className="text-center py-20 text-slate-400 font-bold">Aucune commande en attente.</div>}
            </div>
          )}

          {currentTab === 'inventory' && (
            <div className="bg-white border border-slate-200 rounded-[2.5rem] overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-50/50 border-b border-slate-200">
                  <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <th className="p-8">Produit</th>
                    <th className="p-8">Prix Vente</th>
                    <th className="p-8">Stock Réel</th>
                    <th className="p-8 text-right">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {products.map(p => (
                    <tr key={p.id} className="hover:bg-slate-50/30 transition-colors">
                      <td className="p-8 flex items-center gap-4">
                        <img src={p.image} className="w-12 h-12 object-contain bg-white rounded-xl border border-slate-100" />
                        <span className="font-bold">{p.name}</span>
                      </td>
                      <td className="p-8 font-black text-indigo-600">{p.salePrice} DH</td>
                      <td className="p-8">
                        <span className={`px-3 py-1 rounded-full text-[10px] font-black ${p.stock < 10 ? 'bg-rose-50 text-rose-600' : 'bg-emerald-50 text-emerald-600'}`}>{p.stock}</span>
                      </td>
                      <td className="p-8 text-right">
                        <button onClick={() => deleteProductFromDb(p.id).then(loadData)} className="text-rose-500 font-bold hover:underline">Supprimer</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>

      {/* Modal Ajout Produit */}
      {isAddModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-xl rounded-[3rem] p-10 shadow-2xl animate-fade-in-scale">
            <h2 className="text-3xl font-black mb-8">Nouveau Produit</h2>
            <form onSubmit={handleAddProduct} className="space-y-6">
              <input type="text" placeholder="Désignation" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none" onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" placeholder="Prix Achat (DH)" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none" onChange={e => setNewProduct({...newProduct, purchasePrice: Number(e.target.value)})} />
                <input type="number" placeholder="Prix Vente (DH)" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none" onChange={e => setNewProduct({...newProduct, salePrice: Number(e.target.value)})} />
              </div>
              <input type="number" placeholder="Quantité Initiale" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none" onChange={e => setNewProduct({...newProduct, stock: Number(e.target.value)})} />
              <input type="text" placeholder="URL Image" required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none" onChange={e => setNewProduct({...newProduct, image: e.target.value})} />
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setIsAddModalOpen(false)} className="flex-1 p-5 bg-slate-100 text-slate-600 rounded-2xl font-black">Annuler</button>
                <button type="submit" className="flex-1 p-5 bg-black text-white rounded-2xl font-black shadow-xl shadow-black/20">Ajouter</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminPage;

import { 
  collection, 
  getDocs, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy, 
  serverTimestamp,
  increment,
  writeBatch,
  getDoc
} from 'firebase/firestore';
import { db } from './firebase';
import { Product, Sale, Order } from '../types';

const PRODUCTS_COL = 'products';
const SALES_COL = 'sales';
const ORDERS_COL = 'orders';

const cleanNum = (val: any): number => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

export const getProducts = async (): Promise<Product[]> => {
  try {
    const q = query(collection(db, PRODUCTS_COL), orderBy('name'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      return {
        id: doc.id,
        ...data,
        purchasePrice: cleanNum(data.purchasePrice),
        salePrice: cleanNum(data.salePrice),
        stock: cleanNum(data.stock),
        availableStock: cleanNum(data.availableStock ?? data.stock),
        totalSold: cleanNum(data.totalSold)
      } as Product;
    });
  } catch (error) {
    console.error("Fetch products failed:", error);
    return [];
  }
};

export const getOrders = async (): Promise<Order[]> => {
  try {
    const q = query(collection(db, ORDERS_COL), orderBy('createdAt', 'desc'));
    const snap = await getDocs(q);
    return snap.docs.map(doc => {
      const data = doc.data();
      let dateValue = data.createdAt;
      if (dateValue && typeof dateValue.toMillis === 'function') dateValue = dateValue.toMillis();
      return { id: doc.id, ...data, createdAt: dateValue || Date.now() } as any;
    });
  } catch (error) {
    return [];
  }
};

export const addOrderToDb = async (order: Omit<Order, 'id' | 'status' | 'createdAt'>) => {
  return await addDoc(collection(db, ORDERS_COL), {
    ...order,
    status: 'pending',
    createdAt: serverTimestamp()
  });
};

export const validateOrderAndProcessStock = async (order: Order) => {
  const batch = writeBatch(db);

  for (const item of order.items) {
    const productRef = doc(db, PRODUCTS_COL, item.id);
    const saleRef = doc(collection(db, SALES_COL));

    // Vérification de sécurité pour éviter le stock négatif
    const pSnap = await getDoc(productRef);
    if (pSnap.exists()) {
      const currentStock = pSnap.data().stock || 0;
      if (currentStock < item.quantity && !pSnap.data().isOrderBased) {
        throw new Error(`Stock insuffisant pour ${item.name}`);
      }
    }

    batch.set(saleRef, {
      productId: item.id,
      productName: item.name,
      quantity: item.quantity,
      totalPrice: item.price * item.quantity,
      profit: (item.price - item.purchasePriceAtTime) * item.quantity,
      date: Date.now()
    });

    batch.update(productRef, {
      availableStock: increment(-item.quantity),
      stock: increment(-item.quantity),
      totalSold: increment(item.quantity)
    });
  }

  batch.delete(doc(db, ORDERS_COL, order.id));
  await batch.commit();
};

// FIX: Added missing deleteOrderFromDb function to resolve import errors in AdminPage.tsx
export const deleteOrderFromDb = async (id: string) => {
  await deleteDoc(doc(db, ORDERS_COL, id));
};

export const addProductToDb = async (product: Omit<Product, 'id'>) => {
  const data = {
    ...product,
    availableStock: cleanNum(product.stock),
    initialStock: cleanNum(product.stock),
    totalSold: 0,
    createdAt: serverTimestamp()
  };
  return await addDoc(collection(db, PRODUCTS_COL), data);
};

export const updateProductInDb = async (id: string, updates: Partial<Product>) => {
  const docRef = doc(db, PRODUCTS_COL, id);
  await updateDoc(docRef, updates);
};

export const deleteProductFromDb = async (id: string) => {
  await deleteDoc(doc(db, PRODUCTS_COL, id));
};

export const getSales = async (): Promise<Sale[]> => {
  try {
    const snap = await getDocs(collection(db, SALES_COL));
    return snap.docs.map(doc => ({ id: doc.id, ...doc.data() } as Sale));
  } catch (error) {
    return [];
  }
};

